-- Match Events - APSL
-- Goals, assists, cards, etc. from match event pages
-- Total Records: 3205
--
-- Architecture: Name-based player lookups (no hardcoded IDs)
-- ━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━

-- Match: 228134
INSERT INTO match_events (match_id, player_id, team_id, event_type_id, minute, assisted_by_player_id)
SELECT
  m.id,
  pl.id,
  t.id,
  (SELECT id FROM match_event_types WHERE name = 'sub_in'),
  71,
  NULL
FROM matches m
JOIN teams t ON t.name = 'WC Predators' AND t.source_system_id = 1
JOIN players pl ON true
JOIN persons per ON pl.person_id = per.id
  AND per.first_name = 'Miguel' AND per.last_name = 'Ross'
WHERE m.external_id = '228134' AND m.source_system_id = 1;

