  m.id,
  pl.id,
  t.id,
  (SELECT id FROM match_event_types WHERE name = 'sub_in'),
  81,
  NULL
FROM matches m
JOIN teams t ON t.name = 'Real Central NJ Soccer' AND t.source_system_id = 1
JOIN players pl ON true
JOIN persons per ON pl.person_id = per.id
  AND per.first_name = 'Giovanni' AND per.last_name = 'Pierleonardi'
WHERE m.external_id = '236251' AND m.source_system_id = 1;

