  m.id,
  pl.id,
  t.id,
  (SELECT id FROM match_event_types WHERE name = 'goal'),
  42,
  NULL
FROM matches m
JOIN teams t ON t.name = 'KO Elites' AND t.source_system_id = 1
JOIN players pl ON true
JOIN persons per ON pl.person_id = per.id
  AND per.first_name = 'Joel' AND per.last_name = 'Agebtossou'
WHERE m.external_id = '236822' AND m.source_system_id = 1;

